    ).toBe(false);
  });

  it("should not highlight for disabled (excluded) dates", () => {
    const endDate = newDate();
    const selectingDate = subDays(endDate, 1);
    const container = renderDay(selectingDate, {
      selectingDate,
      endDate,
      selectsRange: true,
      excludeDates: [selectingDate],
    });
    expect(
      container
